prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task1 ?name1 ?task2 ?name2 WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3c1c7ac2bf4042fe9cd4ed34ce14a188" .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?task1 a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?name1 .
  FILTER(CONTAINS(LCASE(STR(?name1)), "record time") && CONTAINS(LCASE(STR(?name1)), "incident"))

  ?task2 a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?name2 .
  FILTER(CONTAINS(LCASE(STR(?name2)), "end") && CONTAINS(LCASE(STR(?name2)), "call") && CONTAINS(LCASE(STR(?name2)), "note"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?normId ?origId ?modelName ?created ?org WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  FILTER(
    (BOUND(?normId) && STR(?normId) = "3c1c7ac2bf4042fe9cd4ed34ce14a188") ||
    (BOUND(?origId) && STR(?origId) = "3c1c7ac2bf4042fe9cd4ed34ce14a188")
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?choreo
  ?choreoName
  (COUNT(DISTINCT ?task) AS ?taskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3c1c7ac2bf4042fe9cd4ed34ce14a188" .
  ?definitions tai:belongsTo ?model .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo .
  }

  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?taskCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?reachable ?reachableName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3c1c7ac2bf4042fe9cd4ed34ce14a188" .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?t1 a bboExt:ChoreographyTask ;
      tai:belongsTo ?choreo ;
      bbo:name "Record time and incident report in service form" .

  ?t2 a bboExt:ChoreographyTask ;
      tai:belongsTo ?choreo ;
      bbo:name "End the call with a good note" .

  ?t1 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachable .
  OPTIONAL { ?reachable bbo:name ?reachableName . }

  FILTER(?reachable = ?t2)
}
LIMIT 25

